export const SELECTABLE_TEAM_IDS = TEAMS.filter(t => t.selectable).map(t => t.id);
export function getTeamById(id) { return TEAMS.find(t => t.id === id); }
export function getPlayerByName(team, name) { return team?.squad?.find(p => p.name === name || p.zhName === name); }
